fit_expected<std::vector<double>>
continuation_path(const MlRidgeContinuationOptions& opts) {
  std::vector<double> path = opts.alphas;
  if (path.empty()) {
    path = MlRidgeContinuationOptions{}.alphas;
  }

  constexpr double tol = 1e-14;
  for (double alpha : path) {
    if (!std::isfinite(alpha) || alpha < 0.0 || alpha > 1.0) {
      return std::unexpected(make_err(FitError::Kind::NumericIssue,
          "fit_ml_ridge_continuation: alphas must be finite values in [0, 1]"));
    }
  }
  if (opts.include_endpoint) {
    if (path.empty() || std::abs(path.back()) > tol) {
      path.push_back(0.0);
    }
  }
  return path;
}

fit_expected<Eigen::MatrixXd>
target_matrix(const Eigen::MatrixXd& S, MlContinuationTarget target,
              double diagonal_floor, std::size_t block) {
  const Eigen::Index p = S.rows();
  Eigen::VectorXd diag = S.diagonal();
  for (Eigen::Index i = 0; i < p; ++i) {
    if (!std::isfinite(diag(i))) {
      return std::unexpected(make_err(FitError::Kind::NumericIssue,
          "fit_ml_ridge_continuation: sample S for block " +
              std::to_string(block) + " has non-finite diagonal entries"));
    }
    if (diag(i) < diagonal_floor) diag(i) = diagonal_floor;
  }

  if (target == MlContinuationTarget::Diagonal) {
    return diag.asDiagonal();
  }
  if (target == MlContinuationTarget::Identity) {
    return Eigen::MatrixXd::Identity(p, p);
  }

  double scale = diag.mean();
  if (!std::isfinite(scale) || scale < diagonal_floor) {
    scale = diagonal_floor;
  }
  return scale * Eigen::MatrixXd::Identity(p, p);
}

fit_expected<MlRidgeContinuationStep>
make_step_diagnostics(const data::SampleStats& samp, double alpha) {
  MlRidgeContinuationStep out;
  out.alpha = alpha;
  out.min_sample_eigen = std::numeric_limits<double>::infinity();
  out.max_sample_eigen = 0.0;

  for (std::size_t b = 0; b < samp.S.size(); ++b) {
    const Eigen::MatrixXd sym = 0.5 * (samp.S[b] + samp.S[b].transpose());
    Eigen::SelfAdjointEigenSolver<Eigen::MatrixXd> es(sym,
                                                      Eigen::EigenvaluesOnly);
    if (es.info() != Eigen::Success || es.eigenvalues().size() == 0) {
      return std::unexpected(make_err(FitError::Kind::NumericIssue,
          "fit_ml_ridge_continuation: eigen decomposition failed for sample "
          "S block " + std::to_string(b)));
    }
    out.min_sample_eigen =
        std::min(out.min_sample_eigen, es.eigenvalues().minCoeff());
    out.max_sample_eigen =
        std::max(out.max_sample_eigen, es.eigenvalues().maxCoeff());
  }

  if (out.min_sample_eigen > 0.0 &&
      std::isfinite(out.min_sample_eigen) &&
      std::isfinite(out.max_sample_eigen)) {
    out.sample_condition = out.max_sample_eigen / out.min_sample_eigen;
  } else {
    out.sample_condition = std::numeric_limits<double>::infinity();
  }
  return out;
}

fit_expected<data::SampleStats>
ridge_sample_stats(const data::SampleStats& samp, double alpha,
                   MlContinuationTarget target, double diagonal_floor) {
  if (!std::isfinite(diagonal_floor) || diagonal_floor <= 0.0) {
    return std::unexpected(make_err(FitError::Kind::NumericIssue,
        "fit_ml_ridge_continuation: diagonal_floor must be positive"));
  }

  data::SampleStats out = samp;
  for (std::size_t b = 0; b < out.S.size(); ++b) {
    const Eigen::MatrixXd& S = samp.S[b];
    if (S.rows() != S.cols()) {
      return std::unexpected(make_err(FitError::Kind::NumericIssue,
          "fit_ml_ridge_continuation: sample S for block " +
              std::to_string(b) + " is not square"));
    }
    const Eigen::MatrixXd sym = 0.5 * (S + S.transpose());
    if (alpha == 0.0) {
      out.S[b] = S;
      continue;
    }
    auto T = target_matrix(sym, target, diagonal_floor, b);
    if (!T.has_value()) return std::unexpected(T.error());
    out.S[b] = (1.0 - alpha) * sym + alpha * *T;
  }
  return out;
}

