fit_expected<MlRidgeContinuationResult>
fit_ml_ridge_continuation(
    spec::LatentStructure pt, const model::MatrixRep& rep,
    const data::SampleStats& samp, const Eigen::VectorXd& x0, Bounds bounds,
    Backend backend, optim::OptimOptions opts,
    MlRidgeContinuationOptions continuation) {
  auto path_or = continuation_path(continuation);
  if (!path_or.has_value()) return std::unexpected(path_or.error());
  const std::vector<double>& path = *path_or;

  MlRidgeContinuationResult result;
  result.steps.reserve(path.size());

  Eigen::VectorXd current = x0;
  for (double alpha : path) {
    auto stage_samp = ridge_sample_stats(samp, alpha, continuation.target,
                                         continuation.diagonal_floor);
    if (!stage_samp.has_value()) return std::unexpected(stage_samp.error());

    auto diag = make_step_diagnostics(*stage_samp, alpha);
    if (!diag.has_value()) return std::unexpected(diag.error());

    auto est = fit_ml(pt, rep, *stage_samp, current, bounds, backend, opts);
    if (!est.has_value()) {
      const FitError& e = est.error();
      return std::unexpected(make_err(e.kind,
          "fit_ml_ridge_continuation: stage alpha=" + alpha_label(alpha) +
              " failed: " + e.detail,
          e.iterations, e.f_value));
    }

    current = est->theta;
    MlRidgeContinuationStep step = std::move(*diag);
    step.estimates = std::move(*est);
    result.total_iterations += step.estimates.iterations;
    result.total_f_evals += step.estimates.f_evals;
    result.total_g_evals += step.estimates.g_evals;
    result.final = step.estimates;
    result.final_sample_stats = std::move(*stage_samp);
    result.steps.push_back(std::move(step));
  }

  if (result.steps.empty()) {
    return std::unexpected(make_err(FitError::Kind::NumericIssue,
        "fit_ml_ridge_continuation: continuation path is empty"));
  }
  return result;
}

